import HeaderDomainInfo from './HeaderDomainInfo';
import PageLogo from '../Logo/GnuLinuxLogo.svg';
import '../HeaderInfo.css';

const HeaderInfo = () => {
  return (
    <section className="header-info">

      <HeaderDomainInfo
        domainLogo={PageLogo}
        domainURL = "www.unix69.githubio.com"
        pageName = "Unix69"
        className = "header-title-info"
        domainLogoClass = "header-title-info-domain-logo"
        domainUrlClass = "header-title-info-domain-url"/>

    </section>
  );
};

export default HeaderInfo;
